import xml.etree.ElementTree as ETdef print_svg_d_attributes(svg_file):    try:        # Parse the SVG file        tree = ET.parse(svg_file)        root = tree.getroot()        # SVG files often have a namespace; extract it        namespace = ''        if root.tag.startswith('{'):            namespace = root.tag.split('}')[0] + '}'        # Find all <path> elements and print their 'd' attributes        for path in root.findall(f'.//{namespace}path'):            d_attr = path.get('d')            if d_attr:                print(d_attr)            else:                print("Path element has no 'd' attribute.")    except FileNotFoundError:        print(f"Error: File '{svg_file}' not found.")    except ET.ParseError as e:        print(f"Error parsing SVG: {e}")        print_svg_d_attributes("BalatonParkorig.svg")key = input("Wait")